import React, { useState } from 'react';
import { auth } from '../firebase/firebaseConfig';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, GoogleAuthProvider, signInWithPopup } from 'firebase/auth';

export default function Login({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isRegister, setIsRegister] = useState(false);
  const [error, setError] = useState('');

  const handleEmailAuth = async (e) => {
    e.preventDefault();
    try {
      const userCredential = isRegister 
        ? await createUserWithEmailAndPassword(auth, email, password)
        : await signInWithEmailAndPassword(auth, email, password);
      onLogin(userCredential.user);
    } catch (err) {
      setError(err.message);
    }
  };

  const handleGoogleLogin = async () => {
    const provider = new GoogleAuthProvider();
    try {
      const userCredential = await signInWithPopup(auth, provider);
      onLogin(userCredential.user);
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-green-600">
      <div className="bg-white p-8 rounded-2xl shadow-md w-full max-w-md">
        <h2 className="text-2xl font-bold mb-6 text-center">{isRegister ? 'Registro' : 'Login'}</h2>
        <form onSubmit={handleEmailAuth} className="space-y-4">
          <input type="email" placeholder="Correo electrónico" value={email} onChange={e => setEmail(e.target.value)} className="w-full px-4 py-2 border rounded"/>
          <input type="password" placeholder="Contraseña" value={password} onChange={e => setPassword(e.target.value)} className="w-full px-4 py-2 border rounded"/>
          <button type="submit" className="w-full py-2 bg-green-600 text-white rounded">{isRegister ? 'Registrar' : 'Iniciar sesión'}</button>
        </form>
        <button onClick={handleGoogleLogin} className="w-full mt-4 py-2 bg-red-500 text-white rounded">Login con Google</button>
        {error && <p className="text-red-500 mt-2 text-center">{error}</p>}
        <p className="mt-4 text-center text-sm">
          {isRegister ? '¿Ya tienes cuenta?' : '¿No tienes cuenta?'} <span className="text-blue-600 cursor-pointer" onClick={() => setIsRegister(!isRegister)}>{isRegister ? 'Iniciar sesión' : 'Regístrate'}</span>
        </p>
      </div>
    </div>
  );
}
